  window.EXTRA_READ_STORIES.push(...[{"id":"fr-matin","title":"Matin en ville","subtitle":"Morning in the city","trail":"green-circle","categoryId":"fr","sentences":[{"foreign":"Bonjour !","en":"Good morning!"},{"foreign":"Salut. Je viens d'arriver.","en":"Hi. I just arrived."},{"foreign":"Il fait froid, mais le soleil brille.","en":"It's cold, but the sun is shining."},{"foreign":"Je prends un Vélib' le long de la rue piétonne.","en":"I'm taking a Vélib' along the pedestrian street."},{"foreign":"Pardon, où est l'arrêt du tramway ?","en":"Excuse me, where is the tram stop?"},{"foreign":"Tout droit, sur le trottoir, au carrefour.","en":"Straight ahead, on the sidewalk, at the intersection."},{"foreign":"Merci. Est-ce qu'une ligne vers le centre roule maintenant ?","en":"Thanks. Is a line into the center running now?"},{"foreign":"Oui. Regarde l'horaire, ou prends un taxi si tu es pressé.","en":"Yes. Check the timetable, or take a taxi if you're in a hurry."},{"foreign":"Merci beaucoup. Bonne journée !","en":"Thank you so much. Have a nice day!"},{"foreign":"Pas de problème. Bonne chance !","en":"No problem. Good luck!"}],"glosses":{"viens d'arriver":"just arrived","brille":"is shining","Vélib'":"city bike","rue piétonne":"pedestrian street","arrêt":"stop","tramway":"tram","Tout droit":"straight ahead","trottoir":"sidewalk","carrefour":"intersection","ligne":"line","centre":"center","horaire":"timetable","taxi":"taxi","pressé":"in a hurry","Bonne chance":"good luck"}},{"id":"fr-cafe","title":"Un café, s'il vous plaît","subtitle":"Ordering coffee","trail":"green-circle","categoryId":"fr","sentences":[{"foreign":"Salut ! Il y a une place libre ici au café ?","en":"Hi! Is there a free table here in the café?"},{"foreign":"Oui. Vous voulez voir la carte ?","en":"Yes. Would you like to look at the menu?"},{"foreign":"Un café, s'il vous plaît. Sans lait.","en":"One coffee, please. Without milk."},{"foreign":"Vous voulez aussi le petit-déjeuner ? On a du thé, du jus et un sandwich au fromage.","en":"Would you also like to order breakfast? We have tea, juice, and cheese sandwiches."},{"foreign":"Que me conseillez-vous ?","en":"What do you recommend?"},{"foreign":"La soupe végétarienne est bonne aujourd'hui. Un dessert plus tard si vous voulez.","en":"The vegetarian soup is good today. Dessert later if you want."},{"foreign":"Un sandwich au fromage, s'il vous plaît. C'est épicé ?","en":"A cheese sandwich, please. Is it spicy?"},{"foreign":"Non, doux. On est ouvert jusqu'à trois heures. À emporter, c'est possible si vous êtes pressé.","en":"No, mild. We're open until three. Takeaway is fine if you're in a hurry."},{"foreign":"Je peux avoir l'addition maintenant ? Le pourboire se fait ici, non ?","en":"Can I get the bill now? Tipping is done here, right?"},{"foreign":"Oui. Ça fait quarante-cinq euros. Bonne journée !","en":"Yes. That's forty-five euros. Have a nice day!"}],"glosses":{"place libre":"free table","café":"café","carte":"menu","Sans lait":"without milk","petit-déjeuner":"breakfast","thé":"tea","jus":"juice","conseillez":"recommend","végétarienne":"vegetarian","sandwich au fromage":"cheese sandwich","dessert":"dessert","épicé":"spicy","doux":"mild","À emporter":"takeaway","addition":"bill","pourboire":"tip","quarante-cinq":"forty-five"}},{"id":"fr-train","title":"Dans le train","subtitle":"On the train","trail":"green-circle","categoryId":"fr","sentences":[{"foreign":"Ce train va à Paris ?","en":"Does this train go to Paris?"},{"foreign":"Oui, c'est ça. Voie quatre. Prochain départ dans dix minutes.","en":"Yes, that's right. Track four. Next departure in ten minutes."},{"foreign":"Où est-ce que j'achète un billet ? Ça marche avec un abonnement mensuel ?","en":"Where do I buy a ticket? Can I use a monthly pass?"},{"foreign":"Dans l'appli ou au distributeur. Sinon un billet simple suffit.","en":"In the app or at the machine. Otherwise a one-way ticket is fine."},{"foreign":"Billet simple, s'il vous plaît. Fenêtre, si possible. Quelle zone c'est ?","en":"One-way ticket, please. A window seat, if possible. Which zone is it?"},{"foreign":"Zone un à trois. Il y a un peu de retard aux heures de pointe.","en":"Zones one to three. There's a bit of a delay in rush hour."},{"foreign":"Ça prend combien de temps alors ? Je dois prendre une correspondance.","en":"How long does it take then? I need to make a transfer."},{"foreign":"Environ deux heures. Le terminus, c'est Paris Gare de Lyon.","en":"About two hours. The last stop is Paris Gare de Lyon."},{"foreign":"Bien. Il y a un parking à la gare si je viens en voiture la prochaine fois ?","en":"Good. Is there parking at the station if I come by car next time?"},{"foreign":"Oui, mais ça coûte. Bon voyage !","en":"Yes, but it costs. Have a nice trip!"}],"glosses":{"c'est ça":"that's right","Voie":"track","départ":"departure","billet":"ticket","abonnement mensuel":"monthly pass","distributeur":"ticket machine","billet simple":"one-way","zone":"zone","retard":"delay","heures de pointe":"rush hour","correspondance":"transfer","Environ":"about","terminus":"terminus","parking":"parking"}},{"id":"fr-bibliotheque","title":"À la bibliothèque","subtitle":"At the library","trail":"blue-square","categoryId":"fr","sentences":[{"foreign":"Bonjour, je cherche un endroit calme pour étudier.","en":"Hi, I'm looking for a quiet place to study."},{"foreign":"En haut il y a des tables libres près de la fenêtre. La salle de cours est occupée, et le labo aussi.","en":"Upstairs there are free tables by the window. The classroom is busy, and the lab too."},{"foreign":"Vous êtes ouverts jusqu'à quelle heure ?","en":"How late are you open?"},{"foreign":"Jusqu'à neuf heures ce soir. L'amphi ferme plus tôt.","en":"Until nine this evening. The lecture hall closes earlier."},{"foreign":"Je peux emprunter des livres avec ma carte d'étudiant ? J'habite en résidence juste à côté.","en":"Can I borrow books with a student ID? I live in student housing nearby."},{"foreign":"Oui. Tu as besoin de quelque chose sur la liste de lecture du cours ?","en":"Yes. Do you need anything from the reading list for your course?"},{"foreign":"Peut-être plus tard. D'abord j'ai un travail de groupe avec un camarade. Tu peux répéter ça ?","en":"Maybe later. First I have group work with a classmate. Could you repeat that?"},{"foreign":"Pense à prendre des notes. La permanence du prof est demain. L'inscription au labo est en ligne.","en":"Remember to take notes. The teacher's office hours are tomorrow. Lab enrollment is online."},{"foreign":"Merci. J'espère réussir l'examen. Le mémoire viendra plus tard.","en":"Thanks. I hope I'll pass the exam. The thesis comes later."},{"foreign":"Bonne chance pour l'examen la semaine prochaine !","en":"Good luck with the exam next week!"}],"glosses":{"calme":"quiet","étudier":"to study","libres":"free","occupée":"busy","labo":"lab","amphi":"lecture hall","carte d'étudiant":"student ID","résidence":"student housing","liste de lecture":"reading list","cours":"course","travail de groupe":"group work","camarade":"classmate","répéter":"to repeat","notes":"notes","permanence":"office hours","prof":"teacher","inscription":"enrollment","réussir":"to pass","examen":"exam","mémoire":"thesis"}},{"id":"fr-marche","title":"Au marché","subtitle":"At the market","trail":"blue-square","categoryId":"fr","sentences":[{"foreign":"Bonjour. Il y a une promo au supermarché aujourd'hui ?","en":"Hi. Is there a deal at the supermarket today?"},{"foreign":"Oui, les légumes ne sont pas chers. Le poulet est en promo aussi.","en":"Yes, vegetables are cheap. Chicken is on sale too."},{"foreign":"Ça coûte combien, ce fromage ?","en":"How much is that cheese?"},{"foreign":"Trente euros pièce. Vous voulez un sac ?","en":"Thirty euros each. Would you like a bag?"},{"foreign":"Oui, s'il vous plaît. J'en prends deux, et quatre pommes.","en":"Yes, please. I'll take two cheeses and four apples."},{"foreign":"Le caddie est là-bas si vous avez besoin de plus. Les horaires sont sur la porte.","en":"The shopping cart is over there if you need more. Opening hours are on the door."},{"foreign":"Merci. Je peux payer par carte bancaire à la caisse, ou par carte de crédit ?","en":"Thanks. Can I pay with a bank card at the checkout, or a credit card?"},{"foreign":"Les deux. On est presque sans espèces. Voici la monnaie si vous en avez besoin.","en":"Either. We're almost cashless. Here's change if you need it."},{"foreign":"Super. Je cherche aussi un cadeau. Ce pull est trop grand. Vous avez une autre taille ?","en":"Great. I'm also looking for a gift. This sweater is too big. Do you have another size?"},{"foreign":"La cabine d'essayage est là. Vous pouvez l'échanger plus tard, ou demander un remboursement.","en":"The fitting room is there. You can exchange it later, or ask for a refund."},{"foreign":"Le bleu est bien. Au revoir !","en":"Blue is nice. Bye!"}],"glosses":{"promo":"deal","supermarché":"supermarket","légumes":"vegetables","pas chers":"cheap","poulet":"chicken","pièce":"each","sac":"bag","caddie":"shopping cart","horaires":"opening hours","payer":"to pay","carte bancaire":"bank card","caisse":"checkout","espèces":"cash","monnaie":"change","cadeau":"gift","pull":"sweater","trop grand":"too big","taille":"size","échanger":"to exchange","remboursement":"refund","cabine d'essayage":"fitting room"}},{"id":"fr-amis","title":"Nouveaux amis","subtitle":"New friends","trail":"blue-square","categoryId":"fr","sentences":[{"foreign":"Salut, je m'appelle Sam.","en":"Hi, my name is Sam."},{"foreign":"Content de te voir. Je suis Noor.","en":"Nice to see you. I'm Noor."},{"foreign":"Tu viens d'où ?","en":"Where are you from?"},{"foreign":"Du Canada, mais j'habite ici maintenant. Et toi ?","en":"From Canada, but I live here now. And you?"},{"foreign":"D'ici. Tu étudies quoi ?","en":"From here. What do you study?"},{"foreign":"Informatique. Tu as des projets ce week-end ?","en":"Computer science. Do you have plans this weekend?"},{"foreign":"Oui, une petite fête chez un pote. T'es libre ? T'es invité si tu veux.","en":"Yes, a small party at a buddy's place. Are you free? You're invited if you want."},{"foreign":"Avec plaisir ! J'aime traîner avec de nouvelles personnes. Mon hobby, c'est la photographie.","en":"I’d love to! I like hanging out with new people. My hobby is photography."},{"foreign":"Génial. C'est son anniversaire, donc on dit joyeux anniversaire, et santé !","en":"Really nice. It's his birthday, so we say happy birthday, and cheers!"},{"foreign":"Un café après le séminaire demain ? Ou le musée ce week-end ?","en":"Coffee after the seminar tomorrow? Or the museum this weekend?"},{"foreign":"Oui. À bientôt. Prends soin de toi, et on reste en contact !","en":"Yes. See you soon. Take care, and stay in touch!"}],"glosses":{"Content de te voir":"nice to see you","D'ici":"from here","projets":"plans","week-end":"weekend","fête":"party","pote":"buddy","T'es libre":"are you free","invité":"invited","traîner":"hang out","hobby":"hobby","photo":"photography","anniversaire":"birthday","santé":"cheers","séminaire":"seminar","À bientôt":"see you soon","Prends soin de toi":"take care","reste en contact":"stay in touch","photographie":"photography"}},{"id":"fr-travail","title":"Premier jour de travail","subtitle":"First day at work","trail":"black-diamond","categoryId":"fr","sentences":[{"foreign":"Bienvenue dans l'équipe, Sam. Voici le bureau.","en":"Welcome to the team, Sam. This is the office."},{"foreign":"Merci. Je suis un peu nerveux. C'est un temps plein ou un temps partiel ?","en":"Thanks. I'm a bit nervous. Is it full-time or part-time?"},{"foreign":"Temps plein. Après l'embauche, le chef présente le projet.","en":"Full-time. After the hire, the boss presents the project."},{"foreign":"Où est-ce que je peux poser mes affaires ?","en":"Where can I put my things?"},{"foreign":"Ici près de la fenêtre, c'est ton bureau. Le mot de passe, un collègue te le donne.","en":"Here by the window is your desk. You'll get the password from a coworker."},{"foreign":"Si tu as des questions, demande. L'ordre du jour est dans la salle de réunion.","en":"If you have questions, just ask. The agenda is in the meeting room."},{"foreign":"Compris. Qui est mon responsable aujourd'hui ?","en":"Understood. Who is my supervisor today?"},{"foreign":"C'est moi. La date limite de la première facture au client, c'est vendredi.","en":"That's me. The deadline for the first invoice to the client is Friday."},{"foreign":"Ok. Quand arrive le salaire, et je peux télétravailler quelques jours ?","en":"Ok. When does the salary come, and can I work from home some days?"},{"foreign":"Salaire le 15. Regarde la fiche de paie. Télétravail après la période d'essai.","en":"Salary on the 15th. See the payslip. Remote work after the trial period."},{"foreign":"Super. Il y aura un déplacement professionnel plus tard dans l'année ?","en":"Great. Will there be a business trip later in the year?"},{"foreign":"Possible. Bonne chance !","en":"Possibly. Good luck!"}],"glosses":{"équipe":"team","bureau":"office","nerveux":"nervous","temps plein":"full-time","temps partiel":"part-time","embauche":"hire","chef":"boss","projet":"project","mot de passe":"password","collègue":"coworker","ordre du jour":"agenda","salle de réunion":"meeting room","responsable":"supervisor","date limite":"deadline","facture":"invoice","client":"client","salaire":"salary","fiche de paie":"payslip","télétravailler":"work remotely","période d'essai":"trial period","déplacement professionnel":"business trip"}},{"id":"fr-medecin","title":"Chez le médecin","subtitle":"At the doctor's","trail":"black-diamond","categoryId":"fr","sentences":[{"foreign":"Bonjour. Vous avez rendez-vous maintenant ?","en":"Good day. Do you have an appointment now?"},{"foreign":"Oui. Qu'est-ce qui ne va pas ?","en":"Yes. What's the matter?"},{"foreign":"J'ai mal à la gorge depuis deux jours, et mal à la tête. L'oreille aussi.","en":"I've had a sore throat for two days, and a headache. The ear too."},{"foreign":"Vous avez de la fièvre, de la toux ou d'autres symptômes ?","en":"Do you have a fever, a cough, or other symptoms?"},{"foreign":"Un peu de fièvre ce matin, et un peu de toux. Pas de mal au ventre.","en":"A little fever this morning, and a bit of a cough. No stomachache."},{"foreign":"L'infirmière prend d'abord la tension. Dites aaa.","en":"The nurse will take blood pressure first. Say ah."},{"foreign":"Ça ressemble à un rhume léger. Vous avez des allergies ?","en":"It looks like a mild cold. Do you have any allergies?"},{"foreign":"Non. J'ai besoin d'une ordonnance pour des médicaments ?","en":"No. Do I need a prescription for medicine?"},{"foreign":"Pas encore. Repos, de l'eau et du paracétamol. Revenez si ça empire.","en":"Not yet. Rest, water, and paracetamol. Come back if it gets worse."},{"foreign":"Merci beaucoup. Je peux avoir un arrêt de travail si ça empire ?","en":"Thank you. Can I get a sick note if it gets worse?"},{"foreign":"Oui. En urgence : appelez le 15, ou allez aux urgences.","en":"Yes. In an emergency: call 15, or go to A&E / the ER."}],"glosses":{"rendez-vous":"appointment","mal à la gorge":"sore throat","mal à la tête":"headache","oreille":"ear","fièvre":"fever","toux":"cough","symptômes":"symptoms","ventre":"stomach","infirmière":"nurse","tension":"blood pressure","rhume":"cold","allergies":"allergies","ordonnance":"prescription","médicaments":"medicine","paracétamol":"paracetamol","arrêt de travail":"sick note","urgence":"emergency","urgences":"ER"}},{"id":"fr-logement","title":"Chercher une chambre","subtitle":"Looking for a room","trail":"black-diamond","categoryId":"fr","sentences":[{"foreign":"Bonjour, j'appelle pour l'appartement en ligne.","en":"Hi, I'm calling about the apartment online."},{"foreign":"Oui, il est encore libre. Quand voulez-vous le voir ?","en":"Yes, it's still free. When would you like to see it?"},{"foreign":"Cet après-midi, vers trois heures.","en":"This afternoon, around three."},{"foreign":"D'accord. C'est dans le quartier, au troisième étage. C'est une colocation. Vous serez locataire.","en":"Fine. It's in the neighborhood, third floor. It's a shared flat. You'll be a tenant."},{"foreign":"Il y a un ascenseur ? Je n'ai qu'une valise de vêtements. L'hôtel devient trop cher longtemps.","en":"Is there an elevator? I only have a suitcase with clothes. A hotel is too expensive long-term."},{"foreign":"Non, seulement des escaliers. La chambre est lumineuse, et il y a un balcon.","en":"No, only stairs. The bedroom is bright, and there is a balcony."},{"foreign":"Et le salon et la buanderie ? Une fuite dans la salle de bain ?","en":"What about the living room and the laundry room? Any leak in the bathroom?"},{"foreign":"Partagé. Pas de fuite. Le loyer inclut l'internet ; les charges viennent en plus.","en":"Shared. No leak. The rent includes internet; shared costs come extra."},{"foreign":"Et il y a une caution ? Quand est-ce que je reçois les clés ?","en":"And is there a deposit? When do I get keys?"},{"foreign":"Oui, un mois. Le propriétaire vous retrouve à la boîte aux lettres avec le bail.","en":"Yes, one month. The landlord will meet you at the mailbox with the lease."},{"foreign":"Parfait. Prévenez-moi si le voisin se plaint du bruit. Je suis calme.","en":"Great. Let me know if the neighbor complains about noise. I'm quiet."}],"glosses":{"appartement":"apartment","libre":"available","quartier":"neighborhood","colocation":"shared flat","locataire":"tenant","ascenseur":"elevator","valise":"suitcase","hôtel":"hotel","chambre":"bedroom","balcon":"balcony","salon":"living room","buanderie":"laundry room","fuite":"leak","Partagé":"shared","loyer":"rent","charges":"shared costs","caution":"deposit","clés":"keys","propriétaire":"landlord","boîte aux lettres":"mailbox","bail":"lease","voisin":"neighbor","bruit":"noise"}},{"id":"fr-greve","title":"Grève dans le métro","subtitle":"Subway strike","trail":"double-black-diamond","categoryId":"fr","sentences":[{"foreign":"Tu as vu les infos ce matin ?","en":"Did you see the news this morning?"},{"foreign":"Non, qu'est-ce qui s'est passé ?","en":"No, what happened?"},{"foreign":"Demain il y a une grève dans le métro et sur plusieurs lignes.","en":"Tomorrow there's a strike on the subway and on several lines."},{"foreign":"Donc les trains ne roulent pas aux heures de pointe ?","en":"So the trains won't run in rush hour?"},{"foreign":"Beaucoup s'arrêtent. Il y a un bus de substitution depuis le terminus.","en":"Many will stop. There will be a replacement bus from the terminus."},{"foreign":"Je prends le Vélib', même s'il pleut sur le trottoir.","en":"I'll take the Vélib', even if it rains on the sidewalk."},{"foreign":"Malin. Ou tu fais du télétravail demain ?","en":"Smart. Or are you working from home tomorrow?"},{"foreign":"Peut-être. Je parle d'abord au responsable, et je regarde le budget pour un taxi.","en":"Maybe. I'll talk to the manager first, and check the budget for a taxi."},{"foreign":"Le rond-point près de la gare sera le chaos. Prends le tram s'il roule.","en":"The roundabout by the station will be chaos. Take the tram if it runs."},{"foreign":"D'accord. Tiens-moi au courant si le départ est annulé.","en":"Alright. Keep me posted if the departure is cancelled."}],"glosses":{"infos":"news","grève":"strike","métro":"subway","lignes":"lines","heures de pointe":"rush hour","bus de substitution":"replacement bus","terminus":"terminus","Vélib'":"city bike","trottoir":"sidewalk","télétravail":"remote work","responsable":"manager","budget":"budget","taxi":"taxi","rond-point":"roundabout","tram":"tram","départ":"departure","annulé":"cancelled"}},{"id":"fr-debat","title":"Un court débat","subtitle":"A short debate","trail":"double-black-diamond","categoryId":"fr","sentences":[{"foreign":"Je trouve les transports en commun vraiment importants.","en":"I think public transport is really important."},{"foreign":"Pourquoi ?","en":"Why?"},{"foreign":"Parce que tout le monde n'a pas de voiture aux heures de pointe, et les frais de parking sont élevés.","en":"Because not everyone has a car in rush hour, and parking fees are high."},{"foreign":"Mais les bus sont toujours pleins et en retard. Le prix du billet monte aussi.","en":"But the buses are always full and late. The ticket price is rising too."},{"foreign":"Si on investit plus dans les lignes, ça s'améliore. Regarde le budget de la ville.","en":"If we invest more in lines, it gets better. Look at the city budget."},{"foreign":"À long terme, peut-être. Maintenant c'est cher. Les intérêts et les prêts pèsent sur les gens.","en":"In the long run, maybe. Right now it's expensive. Interest and loans put pressure on people."},{"foreign":"Vrai. Quand même, je trouve que ça vaut le coup. On peut verser plus aux transports.","en":"True. Even so, I think it's worth it. You can put more into transport."},{"foreign":"Lisons plus avant de décider. Je regarde mon compte après le déjeuner.","en":"Let's read more before we decide. I'll check my account after lunch."},{"foreign":"D'accord. On se retrouve au distributeur de la gare et on continue.","en":"Alright. We'll meet at the ATM at the station and talk more."}],"glosses":{"transports en commun":"public transport","heures de pointe":"rush hour","frais":"fees","parking":"parking","en retard":"late","billet":"ticket","lignes":"lines","budget":"budget","intérêts":"interest","prêts":"loans","vaut le coup":"worth it","compte":"account","déjeuner":"lunch","distributeur":"ATM"}},{"id":"fr-plans","title":"Projets pour l'été","subtitle":"Summer plans","trail":"double-black-diamond","categoryId":"fr","sentences":[{"foreign":"Tu fais quoi cet été ?","en":"What are you going to do this summer?"},{"foreign":"Je voudrais voyager quelques semaines, si c'est possible. Tu as des projets ?","en":"I want to travel a few weeks, if it works out. Do you have plans?"},{"foreign":"Peut-être en Bretagne. Je réserve un aller-retour dans l'appli ce soir.","en":"Maybe to Brittany. I'm booking a round-trip in the app tonight."},{"foreign":"Tu as le passeport prêt ? Les bagages passent par l'enregistrement et le contrôle des passeports.","en":"Is your passport ready? The luggage has to go through check-in and passport control."},{"foreign":"Oui. Juste un bagage à main. La porte et le siège sont sur la carte d'embarquement après la sécurité.","en":"Yes. Hand luggage only. Gate and seat are on the boarding pass after security."},{"foreign":"L'embarquement commence tôt. Après l'atterrissage, tu récupères la valise sur le tapis.","en":"Boarding starts early. After landing you pick up the suitcase on the baggage carousel."},{"foreign":"Moi je reste et je fais des heures sup. L'épargne va dans mon budget et les mensualités du prêt.","en":"I'm staying and working overtime. The savings go into my budget and loan installments."},{"foreign":"Pratique. Mon vol peut être en retard. L'arrivée est tardive de toute façon.","en":"Practical. My flight might be delayed. Arrival is late either way."},{"foreign":"Préviens-moi quand tu atterris. Le terminal est facile à trouver.","en":"Let me know when you land. The terminal is easy to find."},{"foreign":"Avec plaisir. Tiens-moi au courant. Bon départ !","en":"Will do. Keep me posted. Have a good departure!"}],"glosses":{"projets":"plans","réserve":"am booking","aller-retour":"round-trip","passeport":"passport","bagages":"luggage","enregistrement":"check-in","contrôle des passeports":"passport control","porte":"gate","siège":"seat","carte d'embarquement":"boarding pass","sécurité":"security","embarquement":"boarding","tapis":"baggage carousel","heures sup":"overtime","budget":"budget","mensualités":"installments","prêt":"loan","en retard":"delayed","arrivée":"arrival","atterris":"land","terminal":"terminal","départ":"departure","bagage à main":"hand luggage"}}]);
